using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.AI;

var notes = new List<string>();
var httpClient = new HttpClient();
httpClient.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");

// --- Tool definitions ---

[Description("Searches the web for information on a query and returns relevant snippets.")]
async Task<string> SearchWeb(
    [Description("The search query string")] string query)
{
    Console.ForegroundColor = ConsoleColor.DarkCyan;
    Console.WriteLine($"  🔍 Searching: {query}");
    Console.ResetColor();

    try
    {
        var encoded = Uri.EscapeDataString(query);
        var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";
        var json = await httpClient.GetStringAsync(url);
        var doc = JsonDocument.Parse(json).RootElement;

        var results = new List<string>();

        var abstractText = doc.GetProperty("Abstract").GetString();
        var abstractUrl = doc.GetProperty("AbstractURL").GetString();
        if (!string.IsNullOrWhiteSpace(abstractText))
            results.Add($"[Summary] {abstractText}\nSource: {abstractUrl}");

        var heading = doc.GetProperty("Heading").GetString();
        if (!string.IsNullOrWhiteSpace(heading) && results.Count > 0)
            results.Insert(0, $"Topic: {heading}");

        if (doc.TryGetProperty("RelatedTopics", out var topics))
        {
            foreach (var topic in topics.EnumerateArray().Take(6))
            {
                if (topic.TryGetProperty("Text", out var text) &&
                    topic.TryGetProperty("FirstURL", out var topicUrl))
                {
                    results.Add($"- {text.GetString()}\n  URL: {topicUrl.GetString()}");
                }
            }
        }

        return results.Count == 0
            ? $"No results found for '{query}'. Try rephrasing."
            : string.Join("\n\n", results);
    }
    catch (Exception ex)
    {
        return $"Search error: {ex.Message}";
    }
}

[Description("Saves a research note to the notebook. Use this to record important findings during research.")]
string SaveNote(
    [Description("The content of the note to save")] string content)
{
    notes.Add(content);
    Console.ForegroundColor = ConsoleColor.DarkYellow;
    Console.WriteLine($"  📝 Note #{notes.Count} saved");
    Console.ResetColor();
    return $"Note saved. Total notes: {notes.Count}.";
}

[Description("Retrieves all previously saved research notes.")]
string GetNotes()
{
    if (notes.Count == 0)
        return "No notes have been saved yet.";

    Console.ForegroundColor = ConsoleColor.DarkYellow;
    Console.WriteLine($"  📋 Retrieving {notes.Count} note(s)");
    Console.ResetColor();

    return string.Join("\n---\n",
        notes.Select((n, i) => $"[Note {i + 1}] {n}"));
}

// --- Client setup ---

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to run this agent.");

var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

IChatClient chatClient = new ChatClientBuilder(
        new OpenAI.OpenAIClient(apiKey)
            .GetChatClient(model)
            .AsIChatClient())
    .UseFunctionInvocation()
    .Build();

var chatOptions = new ChatOptions
{
    Tools =
    [
        AIFunctionFactory.Create(SearchWeb),
        AIFunctionFactory.Create(SaveNote),
        AIFunctionFactory.Create(GetNotes),
    ],
};

// --- Main loop ---

Console.ForegroundColor = ConsoleColor.Green;
Console.WriteLine("══════════════════════════════════════════");
Console.WriteLine("          🔬  AI Research Agent");
Console.WriteLine("══════════════════════════════════════════");
Console.ResetColor();
Console.WriteLine("Enter a topic to research, or 'quit' to exit.\n");

while (true)
{
    Console.ForegroundColor = ConsoleColor.White;
    Console.Write("Topic: ");
    Console.ResetColor();

    var topic = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(topic) ||
        topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
        break;

    Console.ForegroundColor = ConsoleColor.DarkGray;
    Console.WriteLine("\nResearching…\n");
    Console.ResetColor();

    List<ChatMessage> messages =
    [
        new(ChatRole.System, """
            You are a research agent. Given a topic you MUST:
            1. Search the web with 2-3 different queries to gather broad information.
            2. Save every important finding as a note using SaveNote.
            3. When done gathering info, call GetNotes and write a structured summary
               that includes key facts, context, and source URLs.
            Be thorough but concise.
            """),
        new(ChatRole.User,
            $"Research this topic and provide a comprehensive summary: {topic}"),
    ];

    try
    {
        var response = await chatClient.GetResponseAsync(messages, chatOptions);

        Console.ForegroundColor = ConsoleColor.Cyan;
        Console.WriteLine("\n━━━ Research Summary ━━━━━━━━━━━━━━━━━━");
        Console.ResetColor();
        Console.WriteLine(response.Text);
        Console.ForegroundColor = ConsoleColor.Cyan;
        Console.WriteLine("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n");
        Console.ResetColor();
    }
    catch (Exception ex)
    {
        Console.ForegroundColor = ConsoleColor.Red;
        Console.WriteLine($"\nError: {ex.Message}\n");
        Console.ResetColor();
    }

    notes.Clear();
}

Console.WriteLine("Goodbye! 👋");

